import React, { useState, useEffect } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { User, LogOut, LayoutDashboard, UserPlus, Search, ShoppingCart } from 'lucide-react';
import { useAuth } from '../context/AuthContext';
import { useCart } from '../context/CartContext';

const Header = () => {
    const navigate = useNavigate();
    const location = useLocation();
    const { user, isAuthenticated, logout } = useAuth();
    const { totalItems } = useCart();
    const [searchTerm, setSearchTerm] = useState("");
    
    const nombreUsuario = user?.nombre || "Usuario";

    useEffect(() => {
        if (location.pathname === '/' && !location.search) {
            setSearchTerm("");
        }
    }, [location]);

    const handleSearch = (e) => {
        e.preventDefault();
        if (searchTerm.trim()) {
            navigate(`/?search=${searchTerm}`);
        } else {
            navigate('/');
        }
    };

    const handleLogoClick = () => {
        setSearchTerm("");
        navigate('/');
    };

    return (
        <header style={headerContainer}>
            <div style={logoSection} onClick={handleLogoClick}>
                <span style={logoWhite}>OFERTAS</span>
                <span style={logoOrange}>APP</span>
            </div>

            {user?.rol !== 'vendedor' && (
                <form onSubmit={handleSearch} style={searchWrapper}>
                    <Search size={18} color="#94a3b8" />
                    <input 
                        type="text" 
                        placeholder="¿Qué buscás hoy?" 
                        style={searchInput}
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                    />
                </form>
            )}

            <nav style={navLinks}>
                {!isAuthenticated ? (
                    <>
                        <Link to="/registro" style={linkWhite}>
                            <UserPlus size={18} /> 
                            <span>Crear cuenta</span>
                        </Link>
                        <Link to="/login" style={loginButton}>Ingresar</Link>
                    </>
                ) : (
                    <div style={{ display: 'flex', alignItems: 'center', gap: '20px' }}>
                        
                        {/* ICONO DE CARRITO */}
                        {user?.rol === 'cliente' && (
                            <div style={cartIconStyle} onClick={() => navigate('/carrito')}>
                                <ShoppingCart size={22} color="white" />
                                {totalItems > 0 && <span style={cartBadge}>{totalItems}</span>}
                            </div>
                        )}

                        <div style={userInfo}>
                            <User size={16} color="#94a3b8" />
                            <span style={{ color: 'white', fontSize: '0.9rem' }}>
                                Hola, <strong style={{ color: '#e67e22' }}>{nombreUsuario}</strong>
                            </span>
                        </div>

                        <button 
                            onClick={() => navigate(user?.rol === 'vendedor' ? '/dashboard' : '/')} 
                            style={panelButton}
                        >
                            <LayoutDashboard size={18} />
                            <span>{user?.rol === 'vendedor' ? 'Mi Comercio' : 'Ir al Súper'}</span>
                        </button>
                        
                        <button 
                            onClick={() => {
                                logout();
                                navigate('/login');
                            }} 
                            style={logoutBtn}
                        >
                            <LogOut size={20} />
                        </button>
                    </div>
                )}
            </nav>
        </header>
    );
};

// --- ESTILOS ---
const headerContainer = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '0 5%', background: '#1e293b', height: '75px', position: 'sticky', top: 0, zIndex: 1000, boxShadow: '0 4px 10px rgba(0,0,0,0.1)', gap: '20px' };
const logoSection = { cursor: 'pointer', fontSize: '1.6rem', fontWeight: '800', minWidth: '180px' };
const logoWhite = { color: '#ffffff' };
const logoOrange = { color: '#e67e22', marginLeft: '2px' };
const searchWrapper = { flex: 1, maxWidth: '400px', display: 'flex', alignItems: 'center', background: 'rgba(255,255,255,0.1)', padding: '8px 15px', borderRadius: '12px', gap: '10px', border: '1px solid rgba(255,255,255,0.1)' };
const searchInput = { background: 'none', border: 'none', outline: 'none', color: 'white', width: '100%', fontSize: '0.9rem' };
const navLinks = { display: 'flex', alignItems: 'center', gap: '25px' };
const linkWhite = { color: '#cbd5e1', textDecoration: 'none', fontSize: '0.9rem', display: 'flex', alignItems: 'center', gap: '8px' };
const loginButton = { background: '#e67e22', color: 'white', padding: '10px 22px', borderRadius: '10px', textDecoration: 'none', fontWeight: 'bold' };
const userInfo = { display: 'flex', alignItems: 'center', gap: '8px', background: 'rgba(255,255,255,0.05)', padding: '6px 12px', borderRadius: '8px' };
const panelButton = { background: 'rgba(230, 126, 34, 0.1)', color: '#e67e22', border: '1px solid #e67e22', padding: '8px 18px', borderRadius: '10px', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px', fontWeight: 'bold' };
const logoutBtn = { background: 'none', border: 'none', color: '#94a3b8', cursor: 'pointer' };

const cartIconStyle = { position: 'relative', cursor: 'pointer', display: 'flex', alignItems: 'center', padding: '8px', background: 'rgba(255,255,255,0.1)', borderRadius: '10px' };
const cartBadge = { position: 'absolute', top: '-5px', right: '-5px', background: '#e67e22', color: 'white', fontSize: '0.7rem', padding: '2px 6px', borderRadius: '10px', fontWeight: 'bold' };

export default Header;
